{
  "name": "TruthLens - Deepfake Detector",
  "description": "Advanced AI-powered image forensic tool to detect deepfakes, AI-generated content, and photo manipulation."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SuspiciousRegion {
  description: string;
  box_2d?: [number, number, number, number]; // [ymin, xmin, ymax, xmax] 0-100 scale
}

export interface AnalysisResult {
  classification: 'Real' | 'AI Generated' | 'Digitally Manipulated' | 'Unknown';
  confidenceScore: number; // 0-100
  verdictSummary: string;
  detailedAnalysis: string[];
  technicalIndicators: {
    lighting: string;
    textures: string;
    anatomy: string;
    artifacts: string;
  };
  suspiciousRegions: SuspiciousRegion[];
  detectedModelSignatures?: string[]; // e.g. "Diffusion Artifacts", "GAN noise"
}

export enum AppState {
  IDLE = 'IDLE',
  PREVIEW = 'PREVIEW',
  ANALYZING = 'ANALYZING',
  RESULT = 'RESULT',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const GEMINI_API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: GEMINI_API_KEY });

export const analyzeImage = async (base64Image: string, mimeType: string): Promise<AnalysisResult> => {
  if (!GEMINI_API_KEY) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  const prompt = `
    You are an expert digital forensics investigator and AI image detector. 
    Analyze the provided image specifically for signs that it is Deepfake, AI-Generated (e.g., by Midjourney, DALL-E, Stable Diffusion, Gemini, "Banana Nano" concept models, GPT-based visualizers) or Photoshop manipulated.

    Look for specific forensic indicators:
    1. Inconsistent lighting and shadows.
    2. Unnatural textures (skin smoothing, hair melding).
    3. Anatomical errors (hands, eyes, teeth).
    4. Text rendering artifacts.
    5. Background blurring inconsistencies.
    6. Pixel-level artifacts indicative of GANs or Diffusion models.

    Return a structured JSON response assessing the authenticity of the image.

    If specific regions are fake, identify them with bounding boxes (0-100 scale for ymin, xmin, ymax, xmax).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image
            }
          },
          {
            text: prompt
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            classification: {
              type: Type.STRING,
              enum: ['Real', 'AI Generated', 'Digitally Manipulated', 'Unknown'],
              description: "The final verdict on the image source."
            },
            confidenceScore: {
              type: Type.NUMBER,
              description: "Confidence in the classification from 0 to 100."
            },
            verdictSummary: {
              type: Type.STRING,
              description: "A concise 1-2 sentence conclusion."
            },
            detailedAnalysis: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "List of 3-5 detailed observations supporting the verdict."
            },
            technicalIndicators: {
              type: Type.OBJECT,
              properties: {
                lighting: { type: Type.STRING },
                textures: { type: Type.STRING },
                anatomy: { type: Type.STRING },
                artifacts: { type: Type.STRING }
              }
            },
            suspiciousRegions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  description: { type: Type.STRING },
                  box_2d: {
                    type: Type.ARRAY,
                    items: { type: Type.NUMBER },
                    description: "[ymin, xmin, ymax, xmax] in 0-100 scale"
                  }
                }
              }
            },
            detectedModelSignatures: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Possible models used (e.g. 'Stable Diffusion', 'Midjourney', 'Photoshop')"
            }
          },
          required: ["classification", "confidenceScore", "verdictSummary", "detailedAnalysis", "technicalIndicators"]
        }
      }
    });

    const resultText = response.text;
    if (!resultText) {
      throw new Error("Empty response from AI");
    }

    return JSON.parse(resultText) as AnalysisResult;

  } catch (error) {
    console.error("Analysis Failed", error);
    throw new Error("Failed to analyze image. Please try again.");
  }
};

import React from 'react';

interface ScannerProps {
  active: boolean;
}

const Scanner: React.FC<ScannerProps> = ({ active }) => {
  if (!active) return null;

  return (
    <div className="absolute inset-0 pointer-events-none overflow-hidden rounded-lg z-10">
      {/* Grid Overlay */}
      <div className="absolute inset-0 opacity-20 bg-[linear-gradient(rgba(0,255,255,0.1)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.1)_1px,transparent_1px)] bg-[size:20px_20px]"></div>

      {/* Moving Scan Line */}
      <div className="scan-line"></div>

      {/* Corner Brackets */}
      <div className="absolute top-4 left-4 w-8 h-8 border-t-2 border-l-2 border-cyan-500"></div>
      <div className="absolute top-4 right-4 w-8 h-8 border-t-2 border-r-2 border-cyan-500"></div>
      <div className="absolute bottom-4 left-4 w-8 h-8 border-b-2 border-l-2 border-cyan-500"></div>
      <div className="absolute bottom-4 right-4 w-8 h-8 border-b-2 border-r-2 border-cyan-500"></div>

      {/* Status Text */}
      <div className="absolute bottom-6 right-6 font-mono text-cyan-400 text-sm animate-pulse">
        SCANNING_LAYERS...
      </div>
    </div>
  );
};

export default Scanner;

import React from 'react';
import { AnalysisResult } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip } from 'recharts';

interface ResultDashboardProps {
  result: AnalysisResult;
}

const ResultDashboard: React.FC<ResultDashboardProps> = ({ result }) => {
  const isFake = result.classification !== 'Real';
  const color = isFake ? '#ef4444' : '#22c55e'; // Red for fake, Green for real

  const scoreData = [
    { name: 'Confidence', value: result.confidenceScore },
    { name: 'Uncertainty', value: 100 - result.confidenceScore }
  ];

  return (
    <div className="w-full bg-gray-900 border border-gray-800 rounded-xl p-6 shadow-2xl animate-in fade-in slide-in-from-bottom-4 duration-700">

      {/* Header / Verdict */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 border-b border-gray-800 pb-6">
        <div>
          <h2 className="text-gray-400 text-sm font-mono mb-1 tracking-widest uppercase">Detection Verdict</h2>
          <h1 className={`text-4xl md:text-5xl font-bold font-display ${isFake ? 'text-red-500' : 'text-green-500'} drop-shadow-lg`}>
            {result.classification.toUpperCase()}
          </h1>
        </div>
        <div className="mt-4 md:mt-0 flex items-center gap-4 bg-gray-950 p-4 rounded-lg border border-gray-800">
          <div className="h-16 w-16">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={scoreData}
                  cx="50%"
                  cy="50%"
                  innerRadius={20}
                  outerRadius={30}
                  startAngle={90}
                  endAngle={-270}
                  dataKey="value"
                  stroke="none"
                >
                  <Cell fill={color} />
                  <Cell fill="#374151" />
                </Pie>
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div>
            <div className="text-2xl font-bold text-white">{result.confidenceScore}%</div>
            <div className="text-xs text-gray-500 uppercase">Confidence Score</div>
          </div>
        </div>
      </div>

      {/* Summary */}
      <div className="mb-8 p-4 bg-gray-950/50 rounded-lg border-l-4 border-cyan-500">
        <h3 className="text-cyan-400 font-bold mb-2 flex items-center gap-2">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          Executive Summary
        </h3>
        <p className="text-gray-300 leading-relaxed text-lg">{result.verdictSummary}</p>
      </div>

      {/* Grid Layout for Details */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* Technical Indicators */}
        <div className="space-y-6">
          <h3 className="text-xl font-bold text-white mb-4 border-b border-gray-800 pb-2">Technical Indicators</h3>

          <div className="grid grid-cols-1 gap-4">
            <IndicatorCard label="Lighting & Shadows" value={result.technicalIndicators.lighting} icon="sun" />
            <IndicatorCard label="Texture Analysis" value={result.technicalIndicators.textures} icon="fingerprint" />
            <IndicatorCard label="Anatomy & Logic" value={result.technicalIndicators.anatomy} icon="user" />
            <IndicatorCard label="Digital Artifacts" value={result.technicalIndicators.artifacts} icon="cpu" />
          </div>
        </div>

        {/* Detailed Analysis & Signatures */}
        <div className="space-y-6">
          <h3 className="text-xl font-bold text-white mb-4 border-b border-gray-800 pb-2">Forensic Breakdown</h3>
          <ul className="space-y-3">
            {result.detailedAnalysis.map((point, i) => (
              <li key={i} className="flex items-start gap-3 text-gray-300">
                <span className="mt-1.5 w-1.5 h-1.5 rounded-full bg-cyan-500 flex-shrink-0" />
                <span>{point}</span>
              </li>
            ))}
          </ul>

          {result.detectedModelSignatures && result.detectedModelSignatures.length > 0 && (
            <div className="mt-6 pt-6 border-t border-gray-800">
              <h4 className="text-sm text-gray-500 uppercase tracking-widest mb-3">Detected Patterns Compatible With</h4>
              <div className="flex flex-wrap gap-2">
                {result.detectedModelSignatures.map((sig, i) => (
                  <span key={i} className="px-3 py-1 bg-red-900/30 text-red-400 border border-red-900/50 rounded-full text-xs font-mono">
                    {sig}
                  </span>
                ))}
              </div>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

const IndicatorCard = ({ label, value, icon }: { label: string, value: string, icon: string }) => (
  <div className="bg-gray-800/50 p-4 rounded-lg border border-gray-700 hover:border-gray-600 transition-colors">
    <div className="text-xs text-gray-500 uppercase font-bold mb-1 flex items-center gap-2">
      {/* Simple Icons based on string name */}
      {icon === 'sun' && <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" /></svg>}
      {icon === 'fingerprint' && <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 11c0 3.517-1.009 6.799-2.753 9.571m-3.44-2.04l.054-.09A13.916 13.916 0 008 11a4 4 0 118 0c0 1.017-.07 2.019-.203 3m-2.118 6.844A21.88 21.88 0 0015.171 17m3.839 1.132c.645-2.266.99-4.659.99-7.131A8 8 0 008 4.07M3 15.364c.64-1.319 1-2.8 1-4.364 0-1.457.2-2.858.59-4.18" /></svg>}
      {icon === 'user' && <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>}
      {icon === 'cpu' && <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2zM9 9h6v6H9V9z" /></svg>}

      {label}
    </div>
    <div className="text-gray-200 text-sm">{value}</div>
  </div>
);

export default ResultDashboard;

import React, { useState, useRef, useEffect } from 'react';
import { AppState, AnalysisResult, SuspiciousRegion } from './types';
import { analyzeImage } from './services/geminiService';
import Scanner from './components/Scanner';
import ResultDashboard from './components/ResultDashboard';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [imageSrc, setImageSrc] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>('');
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>('');
  const [imageDimensions, setImageDimensions] = useState<{width: number, height: number} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const processFile = (file: File) => {
    if (!file.type.startsWith('image/')) {
      setErrorMsg('Please upload a valid image file.');
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      setImageSrc(result);
      setMimeType(file.type);
      setAppState(AppState.PREVIEW);
      setErrorMsg('');
      setAnalysisResult(null);
    };
    reader.readAsDataURL(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const triggerAnalysis = async () => {
    if (!imageSrc) return;

    setAppState(AppState.ANALYZING);
    try {
      // Extract base64 content
      const base64Data = imageSrc.split(',')[1];
      const result = await analyzeImage(base64Data, mimeType);
      setAnalysisResult(result);
      setAppState(AppState.RESULT);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || 'Analysis failed');
      setAppState(AppState.ERROR);
    }
  };

  const reset = () => {
    setAppState(AppState.IDLE);
    setImageSrc(null);
    setAnalysisResult(null);
    setErrorMsg('');
  };

  const onImageLoad = (e: React.SyntheticEvent<HTMLImageElement>) => {
    const { naturalWidth, naturalHeight } = e.currentTarget;
    setImageDimensions({ width: naturalWidth, height: naturalHeight });
  };

  // Helper to render bounding boxes overlay
  const renderOverlays = () => {
    if (appState !== AppState.RESULT || !analysisResult?.suspiciousRegions || !imageDimensions) return null;

    return analysisResult.suspiciousRegions.map((region, idx) => {
      if (!region.box_2d || region.box_2d.length !== 4) return null;

      const [ymin, xmin, ymax, xmax] = region.box_2d;

      const style = {
        top: `${ymin}%`,
        left: `${xmin}%`,
        height: `${ymax - ymin}%`,
        width: `${xmax - xmin}%`,
      };

      return (
        <div key={idx} className="absolute border-2 border-red-500 bg-red-500/20 group z-20" style={style}>
           <div className="absolute -top-7 left-0 bg-red-600 text-white text-[10px] px-2 py-0.5 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap z-30">
             {region.description}
           </div>
        </div>
      );
    });
  };

  return (
    <div className="min-h-screen bg-gray-950 text-white flex flex-col">
      {/* Navbar */}
      <nav className="border-b border-gray-800 bg-gray-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-gradient-to-tr from-cyan-500 to-blue-600 rounded-lg flex items-center justify-center">
              <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
              </svg>
            </div>
            <span className="font-display font-bold text-xl tracking-tight">TruthLens</span>
          </div>
          <a href="https://ai.google.dev" target="_blank" rel="noreferrer" className="text-xs font-mono text-gray-500 hover:text-cyan-400 transition-colors">
            POWERED BY GEMINI PRO VISION
          </a>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-grow flex flex-col items-center py-12 px-4 max-w-7xl mx-auto w-full">

        {/* Header Section */}
        <div className="text-center mb-12 max-w-2xl">
          <h1 className="text-4xl md:text-6xl font-display font-bold mb-4 bg-clip-text text-transparent bg-gradient-to-r from-white via-gray-200 to-gray-500">
            Deepfake Detector
          </h1>
          <p className="text-gray-400 text-lg">
            Upload an image to detect signatures of Generative AI (GANs, Diffusion) or digital manipulation.
            <br />
            <span className="text-sm text-gray-600 mt-2 block">Supports: Gemini, DALL-E 3, Midjourney, Photoshop, FaceSwap</span>
          </p>
        </div>

        {/* Error Message */}
        {errorMsg && (
          <div className="w-full max-w-xl bg-red-900/20 border border-red-800 text-red-200 px-4 py-3 rounded-lg mb-6 flex items-center gap-3">
             <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
             {errorMsg}
          </div>
        )}

        {/* Workspace Grid */}
        <div className={`w-full grid gap-8 ${appState === AppState.RESULT ? 'grid-cols-1 lg:grid-cols-12' : 'grid-cols-1'}`}>

          {/* Left Col: Image Viewer / Uploader */}
          <div className={`transition-all duration-500 ${appState === AppState.RESULT ? 'lg:col-span-5' : 'max-w-2xl mx-auto w-full'}`}>

            {/* Drop Zone */}
            {appState === AppState.IDLE && (
              <div 
                className="border-2 border-dashed border-gray-700 bg-gray-900/50 rounded-2xl p-12 text-center hover:border-cyan-500/50 hover:bg-gray-800/50 transition-all cursor-pointer group h-96 flex flex-col items-center justify-center"
                onDragOver={handleDragOver}
                onDrop={handleDrop}
                onClick={() => fileInputRef.current?.click()}
              >
                <div className="w-16 h-16 bg-gray-800 rounded-full flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
                  <svg className="w-8 h-8 text-cyan-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                </div>
                <h3 className="text-xl font-medium text-white mb-2">Drag & Drop or Click to Upload</h3>
                <p className="text-gray-500 text-sm">JPEG, PNG, WEBP supported</p>
                <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
              </div>
            )}

            {/* Image Preview Area */}
            {imageSrc && (
              <div className="relative rounded-xl overflow-hidden shadow-2xl border border-gray-800 bg-black">
                {/* Visual Overlays */}
                <Scanner active={appState === AppState.ANALYZING} />
                {renderOverlays()}

                <img 
                  ref={imageRef}
                  src={imageSrc} 
                  alt="Analysis Subject" 
                  className={`w-full h-auto object-contain max-h-[70vh] ${appState === AppState.ANALYZING ? 'opacity-50 blur-sm scale-105' : 'opacity-100'} transition-all duration-1000`}
                  onLoad={onImageLoad}
                />

                {/* Image Controls overlay */}
                <div className="absolute top-4 right-4 flex gap-2 z-30">
                  <button 
                    onClick={reset}
                    className="bg-black/50 hover:bg-black/80 text-white p-2 rounded-lg backdrop-blur-sm border border-white/10 transition-colors"
                    title="Upload new image"
                  >
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
              </div>
            )}

            {/* Action Buttons */}
            {appState === AppState.PREVIEW && (
              <button 
                onClick={triggerAnalysis}
                className="w-full mt-6 bg-cyan-600 hover:bg-cyan-500 text-white font-bold py-4 px-6 rounded-xl shadow-lg shadow-cyan-900/20 transition-all flex items-center justify-center gap-2"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
                ANALYZE IMAGE
              </button>
            )}

            {appState === AppState.ERROR && (
               <button 
               onClick={triggerAnalysis}
               className="w-full mt-6 bg-gray-700 hover:bg-gray-600 text-white font-bold py-3 px-6 rounded-xl transition-all"
             >
               Retry Analysis
             </button>
            )}
          </div>

          {/* Right Col: Results */}
          {appState === AppState.RESULT && analysisResult && (
             <div className="lg:col-span-7">
               <ResultDashboard result={analysisResult} />
             </div>
          )}

        </div>
      </main>

      {/* Footer */}
      <footer className="border-t border-gray-900 py-8 text-center text-gray-600 text-sm">
        <p>&copy; {new Date().getFullYear()} TruthLens AI Forensics. Not for legal use.</p>
      </footer>
    </div>
  );
};

export default App;

export interface SuspiciousRegion {
  description: string;
  box_2d?: [number, number, number, number]; // [ymin, xmin, ymax, xmax] 0-100 scale
}

export interface AdvancedMetrics {
  noiseDistribution: { name: string; value: number }[]; // For frequency analysis chart
  errorLevelAnalysis: number; // 0-100 score
  colorSpaceConsistency: number; // 0-100 score
  compressionArtifacts: number; // 0-100 score
  mathematicalLogicScore: number; // 0-100 score based on geometry
  detectedGenerator?: string; // Specific guess at architecture (e.g. StyleGAN2, AdaIN)
  tensorGradientDescription: string; // Jargon-heavy description of the vector field
}

export interface AnalysisResult {
  classification: 'Real' | 'AI Generated' | 'Digitally Manipulated' | 'Unknown';
  confidenceScore: number; // 0-100
  verdictSummary: string;
  detailedAnalysis: string[];
  technicalIndicators: {
    lighting: string;
    textures: string;
    anatomy: string;
    artifacts: string;
  };
  suspiciousRegions: SuspiciousRegion[];
  detectedModelSignatures?: string[];
  advancedMetrics?: AdvancedMetrics; // Optional, only populated on advanced scan
}

export enum AppState {
  IDLE = 'IDLE',
  PREVIEW = 'PREVIEW',
  ANALYZING = 'ANALYZING',
  RESULT = 'RESULT',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const GEMINI_API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: GEMINI_API_KEY });

export const analyzeImage = async (base64Image: string, mimeType: string, isAdvanced: boolean = false): Promise<AnalysisResult> => {
  if (!GEMINI_API_KEY) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  let systemInstruction = "";
  let promptText = "";

  if (isAdvanced) {
    // The "Super Architecture" Simulation
    systemInstruction = `
      You are 'Neuro-Spectral ResNet-X', a proprietary AI forensics model built on a custom PyTorch architecture.
      You have been trained on a private dataset of 1,000,000 GAN, Diffusion, and "Banana Nano" images, alongside authentic photography.
      Your architecture utilizes 'Chrominance-Flux Variance' and 'Tensor-Flow Continuity' scoring, a method not published in any IEEE paper.

      Perform a deep mathematical breakdown of the image. 
      Analyze the high-frequency noise components, Error Level Analysis (ELA), and pixel-grid alignment.
      Be extremely technical and critical.
    `;
    promptText = `
      Analyze this image using your custom architecture. 
      Detect deepfake signatures from models like GPT-5 Visualizer, Google Banana Nano, Midjourney v6, and Flux.

      Calculate the following specific mathematical metrics (0-100 scale):
      1. Error Level Analysis (ELA) score.
      2. Color Space Consistency.
      3. Compression Artifact Coherence.
      4. Mathematical Logic Score (geometry/perspective).

      Provide a noise distribution dataset for a graph (Low Freq, Mid Freq, High Freq anomalies).

      Identify specific generator architectures if possible (e.g., "Latent Diffusion U-Net", "Transformer-based GAN").
    `;
  } else {
    // Standard Analysis
    systemInstruction = `You are an expert digital forensics investigator.`;
    promptText = `
      Analyze the provided image for signs that it is Deepfake, AI-Generated, or Photoshop manipulated.
      Look for: Inconsistent lighting, unnatural textures, anatomical errors, and text artifacts.
    `;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Image } },
          { text: promptText }
        ]
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            classification: {
              type: Type.STRING,
              enum: ['Real', 'AI Generated', 'Digitally Manipulated', 'Unknown'],
              description: "The final verdict."
            },
            confidenceScore: { type: Type.NUMBER },
            verdictSummary: { type: Type.STRING },
            detailedAnalysis: { type: Type.ARRAY, items: { type: Type.STRING } },
            technicalIndicators: {
              type: Type.OBJECT,
              properties: {
                lighting: { type: Type.STRING },
                textures: { type: Type.STRING },
                anatomy: { type: Type.STRING },
                artifacts: { type: Type.STRING }
              }
            },
            suspiciousRegions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  description: { type: Type.STRING },
                  box_2d: { type: Type.ARRAY, items: { type: Type.NUMBER } }
                }
              }
            },
            detectedModelSignatures: { type: Type.ARRAY, items: { type: Type.STRING } },
            // Advanced Fields (Optional in schema, but requested in prompt if advanced)
            advancedMetrics: {
              type: Type.OBJECT,
              properties: {
                noiseDistribution: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                },
                errorLevelAnalysis: { type: Type.NUMBER },
                colorSpaceConsistency: { type: Type.NUMBER },
                compressionArtifacts: { type: Type.NUMBER },
                mathematicalLogicScore: { type: Type.NUMBER },
                detectedGenerator: { type: Type.STRING },
                tensorGradientDescription: { type: Type.STRING }
              }
            }
          },
          required: ["classification", "confidenceScore", "verdictSummary", "detailedAnalysis", "technicalIndicators"]
        }
      }
    });

    const resultText = response.text;
    if (!resultText) throw new Error("Empty response from AI");

    return JSON.parse(resultText) as AnalysisResult;

  } catch (error) {
    console.error("Analysis Failed", error);
    throw new Error("Failed to analyze image. Please try again.");
  }
};

