export interface SuspiciousRegion {
  description: string;
  box_2d?: [number, number, number, number]; // [ymin, xmin, ymax, xmax] 0-100 scale
}

export interface AdvancedMetrics {
  noiseDistribution: { name: string; value: number }[]; // For frequency analysis chart
  errorLevelAnalysis: number; // 0-100 score
  colorSpaceConsistency: number; // 0-100 score
  compressionArtifacts: number; // 0-100 score
  mathematicalLogicScore: number; // 0-100 score based on geometry
  detectedGenerator?: string; // Specific guess at architecture (e.g. StyleGAN2, AdaIN)
  tensorGradientDescription: string; // Jargon-heavy description of the vector field
}

export interface AnalysisResult {
  classification: 'Real' | 'AI Generated' | 'Digitally Manipulated' | 'Unknown';
  confidenceScore: number; // 0-100
  verdictSummary: string;
  detailedAnalysis: string[];
  technicalIndicators: {
    lighting: string;
    textures: string;
    anatomy: string;
    artifacts: string;
  };
  suspiciousRegions: SuspiciousRegion[];
  detectedModelSignatures?: string[];
  advancedMetrics?: AdvancedMetrics; // Optional, only populated on advanced scan
}

export enum AppState {
  IDLE = 'IDLE',
  TRAINING = 'TRAINING',
  PREVIEW = 'PREVIEW',
  ANALYZING = 'ANALYZING',
  RESULT = 'RESULT',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const GEMINI_API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: GEMINI_API_KEY });

export const analyzeImage = async (base64Image: string, mimeType: string, isAdvanced: boolean = false, isCustomTrained: boolean = false): Promise<AnalysisResult> => {
  if (!GEMINI_API_KEY) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  let systemInstruction = "";
  let promptText = "";

  if (isAdvanced) {
    // The "Super Architecture" Simulation
    const modelVersion = isCustomTrained ? "v2.0 (Fine-Tuned Custom Weights)" : "v1.0 (Base)";
    const trainingContext = isCustomTrained 
      ? "You have recently undergone rigorous fine-tuning on a specialized user-provided dataset of high-difficulty deepfakes. Your sensitivity to 'Diffusion Noise' and 'GAN Artifacts' is maximized." 
      : "You have been trained on a private dataset of 1,000,000 GAN, Diffusion, and 'Banana Nano' images.";

    systemInstruction = `
      You are 'Neuro-Spectral ResNet-X' ${modelVersion}, a proprietary AI forensics model built on a custom PyTorch architecture.
      ${trainingContext}
      Your architecture utilizes 'Chrominance-Flux Variance' and 'Tensor-Flow Continuity' scoring, a method not published in any IEEE paper.

      Perform a deep mathematical breakdown of the image. 
      Analyze the high-frequency noise components, Error Level Analysis (ELA), and pixel-grid alignment.
      Be extremely technical and critical.
    `;

    promptText = `
      Analyze this image using your custom architecture (${modelVersion}). 
      Detect deepfake signatures from models like GPT-5 Visualizer, Google Banana Nano, Midjourney v6, and Flux.

      Calculate the following specific mathematical metrics (0-100 scale):
      1. Error Level Analysis (ELA) score.
      2. Color Space Consistency.
      3. Compression Artifact Coherence.
      4. Mathematical Logic Score (geometry/perspective).

      Provide a noise distribution dataset for a graph (Low Freq, Mid Freq, High Freq anomalies).

      Identify specific generator architectures if possible (e.g., "Latent Diffusion U-Net", "Transformer-based GAN").
    `;
  } else {
    // Standard Analysis
    systemInstruction = `You are an expert digital forensics investigator.`;
    promptText = `
      Analyze the provided image for signs that it is Deepfake, AI-Generated, or Photoshop manipulated.
      Look for: Inconsistent lighting, unnatural textures, anatomical errors, and text artifacts.
    `;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Image } },
          { text: promptText }
        ]
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            classification: {
              type: Type.STRING,
              enum: ['Real', 'AI Generated', 'Digitally Manipulated', 'Unknown'],
              description: "The final verdict."
            },
            confidenceScore: { type: Type.NUMBER },
            verdictSummary: { type: Type.STRING },
            detailedAnalysis: { type: Type.ARRAY, items: { type: Type.STRING } },
            technicalIndicators: {
              type: Type.OBJECT,
              properties: {
                lighting: { type: Type.STRING },
                textures: { type: Type.STRING },
                anatomy: { type: Type.STRING },
                artifacts: { type: Type.STRING }
              }
            },
            suspiciousRegions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  description: { type: Type.STRING },
                  box_2d: { type: Type.ARRAY, items: { type: Type.NUMBER } }
                }
              }
            },
            detectedModelSignatures: { type: Type.ARRAY, items: { type: Type.STRING } },
            // Advanced Fields (Optional in schema, but requested in prompt if advanced)
            advancedMetrics: {
              type: Type.OBJECT,
              properties: {
                noiseDistribution: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                },
                errorLevelAnalysis: { type: Type.NUMBER },
                colorSpaceConsistency: { type: Type.NUMBER },
                compressionArtifacts: { type: Type.NUMBER },
                mathematicalLogicScore: { type: Type.NUMBER },
                detectedGenerator: { type: Type.STRING },
                tensorGradientDescription: { type: Type.STRING }
              }
            }
          },
          required: ["classification", "confidenceScore", "verdictSummary", "detailedAnalysis", "technicalIndicators"]
        }
      }
    });

    const resultText = response.text;
    if (!resultText) throw new Error("Empty response from AI");

    return JSON.parse(resultText) as AnalysisResult;

  } catch (error) {
    console.error("Analysis Failed", error);
    throw new Error("Failed to analyze image. Please try again.");
  }
};

import React, { useEffect, useState, useRef } from 'react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

interface TrainingViewProps {
  onComplete: () => void;
}

const TrainingView: React.FC<TrainingViewProps> = ({ onComplete }) => {
  const [logs, setLogs] = useState<string[]>([]);
  const [progress, setProgress] = useState(0);
  const [lossData, setLossData] = useState<{ step: number; loss: number }[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    let step = 0;
    const maxSteps = 50;

    const interval = setInterval(() => {
      step++;
      const currentProgress = (step / maxSteps) * 100;
      setProgress(currentProgress);

      // Simulate Loss decreasing
      const randomFluctuation = Math.random() * 0.1;
      const simulatedLoss = Math.max(0.01, 2.5 * Math.exp(-0.1 * step) + randomFluctuation);

      setLossData(prev => [...prev, { step, loss: simulatedLoss }]);

      // Generate fake log messages
      const messages = [
        `Epoch ${Math.ceil(step / 5)}/${maxSteps/5} | Batch ${step*12} | LR: 0.001`,
        `[GPU-0] Optimizing gradients... Loss: ${simulatedLoss.toFixed(4)}`,
        `[ResNet-X] Updating tensor weights...`,
        `Validating batch integrity... OK`,
        `Applying Backpropagation...`,
        `Analyzing Feature Map consistency...`
      ];

      setLogs(prev => [...prev, messages[Math.floor(Math.random() * messages.length)]]);

      if (scrollRef.current) {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }

      if (step >= maxSteps) {
        clearInterval(interval);
        setLogs(prev => [...prev, "TRAINING COMPLETE. WEIGHTS UPDATED.", "SYSTEM READY."]);
        setTimeout(onComplete, 1500);
      }
    }, 150); // Speed of training simulation

    return () => clearInterval(interval);
  }, [onComplete]);

  return (
    <div className="flex flex-col items-center justify-center w-full max-w-4xl mx-auto h-[600px] bg-black border border-green-900 rounded-xl overflow-hidden shadow-2xl relative font-mono text-green-500 p-8">
      {/* Background Matrix Effect (CSS) */}
      <div className="absolute inset-0 bg-[url('https://media.giphy.com/media/U3qYN8S0j3bpK/giphy.gif')] opacity-5 pointer-events-none bg-cover"></div>

      <div className="z-10 w-full flex flex-col h-full gap-6">

        {/* Header */}
        <div className="flex justify-between items-end border-b border-green-800 pb-4">
          <div>
            <h2 className="text-2xl font-bold animate-pulse">TRAINING NEURO-SPECTRAL MODEL</h2>
            <p className="text-sm opacity-70">Architecture: ResNet-X Custom | Dataset: 1,000,000 Samples</p>
          </div>
          <div className="text-right">
             <div className="text-3xl font-bold">{Math.round(progress)}%</div>
             <div className="text-xs">COMPLETION</div>
          </div>
        </div>

        {/* Visualization Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 h-full min-h-0">

          {/* Terminal Logs */}
          <div 
            ref={scrollRef}
            className="bg-gray-900/80 border border-green-900/50 p-4 rounded text-xs font-mono overflow-y-auto h-64 md:h-full shadow-inner"
          >
            {logs.map((log, i) => (
              <div key={i} className="mb-1 border-l-2 border-green-700 pl-2">
                <span className="opacity-50">{new Date().toLocaleTimeString()}</span> {">"} {log}
              </div>
            ))}
            <div className="animate-pulse">_</div>
          </div>

          {/* Loss Chart */}
          <div className="bg-gray-900/80 border border-green-900/50 p-4 rounded flex flex-col h-64 md:h-full">
            <h3 className="text-center text-xs uppercase mb-2">Loss Function Optimization</h3>
            <div className="flex-grow">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={lossData}>
                  <defs>
                    <linearGradient id="colorLoss" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#22c55e" stopOpacity={0.8}/>
                      <stop offset="95%" stopColor="#22c55e" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <XAxis dataKey="step" hide />
                  <YAxis hide domain={[0, 3]} />
                  <Tooltip 
                    contentStyle={{backgroundColor: '#000', borderColor: '#22c55e', color: '#22c55e'}} 
                    itemStyle={{color: '#22c55e'}}
                  />
                  <Area type="monotone" dataKey="loss" stroke="#22c55e" fillOpacity={1} fill="url(#colorLoss)" isAnimationActive={false} />
                </AreaChart>
              </ResponsiveContainer>
            </div>
            <div className="flex justify-between text-[10px] mt-2 opacity-60">
              <span>START</span>
              <span>CURRENT EPOCH</span>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

