import React, { useState, useRef, useEffect } from 'react';
import { AppState, AnalysisResult, SuspiciousRegion } from './types';
import { analyzeImage } from './services/geminiService';
import Scanner from './components/Scanner';
import ResultDashboard from './components/ResultDashboard';
import TrainingView from './components/TrainingView';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [imageSrc, setImageSrc] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>('');
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>('');
  const [imageDimensions, setImageDimensions] = useState<{width: number, height: number} | null>(null);
  const [isModelTrained, setIsModelTrained] = useState<boolean>(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const processFile = (file: File) => {
    if (!file.type.startsWith('image/')) {
      setErrorMsg('Please upload a valid image file.');
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      setImageSrc(result);
      setMimeType(file.type);
      setAppState(AppState.PREVIEW);
      setErrorMsg('');
      setAnalysisResult(null);
    };
    reader.readAsDataURL(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const startTraining = () => {
    setAppState(AppState.TRAINING);
  };

  const onTrainingComplete = () => {
    setIsModelTrained(true);
    // If we have an image, go back to preview, else go to idle
    if (imageSrc) {
      setAppState(AppState.PREVIEW);
    } else {
      setAppState(AppState.IDLE);
    }
  };

  const triggerAnalysis = async (isAdvanced: boolean) => {
    if (!imageSrc) return;

    setAppState(AppState.ANALYZING);
    try {
      // Extract base64 content
      const base64Data = imageSrc.split(',')[1];
      const result = await analyzeImage(base64Data, mimeType, isAdvanced, isModelTrained);
      setAnalysisResult(result);
      setAppState(AppState.RESULT);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || 'Analysis failed');
      setAppState(AppState.ERROR);
    }
  };

  const reset = () => {
    setAppState(AppState.IDLE);
    setImageSrc(null);
    setAnalysisResult(null);
    setErrorMsg('');
  };

  const onImageLoad = (e: React.SyntheticEvent<HTMLImageElement>) => {
    const { naturalWidth, naturalHeight } = e.currentTarget;
    setImageDimensions({ width: naturalWidth, height: naturalHeight });
  };

  // Helper to render bounding boxes overlay
  const renderOverlays = () => {
    if (appState !== AppState.RESULT || !analysisResult?.suspiciousRegions || !imageDimensions) return null;

    return analysisResult.suspiciousRegions.map((region, idx) => {
      if (!region.box_2d || region.box_2d.length !== 4) return null;

      const [ymin, xmin, ymax, xmax] = region.box_2d;

      const style = {
        top: `${ymin}%`,
        left: `${xmin}%`,
        height: `${ymax - ymin}%`,
        width: `${xmax - xmin}%`,
      };

      return (
        <div key={idx} className="absolute border-2 border-red-500 bg-red-500/20 group z-20" style={style}>
           <div className="absolute -top-7 left-0 bg-red-600 text-white text-[10px] px-2 py-0.5 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap z-30">
             {region.description}
           </div>
        </div>
      );
    });
  };

  return (
    <div className="min-h-screen bg-gray-950 text-white flex flex-col">
      {/* Navbar */}
      <nav className="border-b border-gray-800 bg-gray-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={reset}>
            <div className="w-8 h-8 bg-gradient-to-tr from-cyan-500 to-blue-600 rounded-lg flex items-center justify-center">
              <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
              </svg>
            </div>
            <span className="font-display font-bold text-xl tracking-tight">TruthLens</span>
          </div>
          <div className="flex items-center gap-4">
             {isModelTrained && (
               <div className="hidden md:flex items-center gap-2 px-3 py-1 bg-green-900/30 border border-green-800 rounded-full">
                 <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                 <span className="text-xs font-mono text-green-400">MODEL V2.0 ACTIVE</span>
               </div>
             )}
             {!isModelTrained && appState !== AppState.TRAINING && (
               <button onClick={startTraining} className="text-xs font-mono text-cyan-400 hover:text-cyan-300 border border-cyan-800 hover:border-cyan-600 px-3 py-1.5 rounded transition-all">
                 TRAIN MODEL
               </button>
             )}
             <a href="https://ai.google.dev" target="_blank" rel="noreferrer" className="hidden sm:block text-xs font-mono text-gray-500 hover:text-cyan-400 transition-colors">
              POWERED BY GEMINI
            </a>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-grow flex flex-col items-center py-12 px-4 max-w-7xl mx-auto w-full">

        {/* Header Section (Hidden during training) */}
        {appState !== AppState.TRAINING && (
          <div className="text-center mb-12 max-w-2xl">
            <h1 className="text-4xl md:text-6xl font-display font-bold mb-4 bg-clip-text text-transparent bg-gradient-to-r from-white via-gray-200 to-gray-500">
              Deepfake Detector
            </h1>
            <p className="text-gray-400 text-lg">
              Upload an image to detect signatures of Generative AI (GANs, Diffusion) or digital manipulation.
            </p>
          </div>
        )}

        {/* Error Message */}
        {errorMsg && (
          <div className="w-full max-w-xl bg-red-900/20 border border-red-800 text-red-200 px-4 py-3 rounded-lg mb-6 flex items-center gap-3">
             <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
             {errorMsg}
          </div>
        )}

        {/* TRAINING VIEW */}
        {appState === AppState.TRAINING && (
          <TrainingView onComplete={onTrainingComplete} />
        )}

        {/* Workspace Grid */}
        {appState !== AppState.TRAINING && (
          <div className={`w-full grid gap-8 ${appState === AppState.RESULT ? 'grid-cols-1 lg:grid-cols-12' : 'grid-cols-1'}`}>

            {/* Left Col: Image Viewer / Uploader */}
            <div className={`transition-all duration-500 ${appState === AppState.RESULT ? 'lg:col-span-5' : 'max-w-2xl mx-auto w-full'}`}>

              {/* Drop Zone */}
              {appState === AppState.IDLE && (
                <div 
                  className="border-2 border-dashed border-gray-700 bg-gray-900/50 rounded-2xl p-12 text-center hover:border-cyan-500/50 hover:bg-gray-800/50 transition-all cursor-pointer group h-96 flex flex-col items-center justify-center"
                  onDragOver={handleDragOver}
                  onDrop={handleDrop}
                  onClick={() => fileInputRef.current?.click()}
                >
